import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testGetCommentMarkerWhenNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getCommentMarker());
    }

    @Test
    void testGetCommentMarkerWhenSetCharacter() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        assertEquals(Character.valueOf('#'), format.getCommentMarker());
    }

    @Test
    void testGetCommentMarkerWhenSetCharacterObject() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker(Character.valueOf(';'));
        assertEquals(Character.valueOf(';'), format.getCommentMarker());
    }
}
